import{_ as a,a as t}from"./chunks/Props_header.D0ErSKhl.js";import{_ as o}from"./chunks/Props_details.3KJ1Ui3s.js";import{_ as r,c as s,o as n,ag as i}from"./chunks/framework.Dnsuz9ka.js";const _=JSON.parse('{"title":"General UI principles","description":"","frontmatter":{"title":"General UI principles"},"headers":[],"relativePath":"general_principles.md","filePath":"general_principles.md"}'),l={name:"general_principles.md"};function p(h,e,c,d,m,u){return n(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="general-ui-principles" tabindex="-1">General UI principles <a class="header-anchor" href="#general-ui-principles" aria-label="Permalink to &quot;General UI principles&quot;">​</a></h1><p>High-level patterns shared across Vue Inspector panels. For <strong>where</strong> the UI runs (overlay, DevTools tab, standalone window), see <a href="/qa-tools/docs/options/display_mode.html">Display modes</a> and <a href="/qa-tools/docs/install.html">Installation</a>.</p><p><img src="'+a+'" alt="Props, полноэкранный режим"></p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>The UI is built around two main tabs: the primary data area and a secondary detail area. In narrow layouts the two can merge into a single working surface.</p><h2 id="working-with-rows" tabindex="-1">Working with rows <a class="header-anchor" href="#working-with-rows" aria-label="Permalink to &quot;Working with rows&quot;">​</a></h2><p>In all tables you can act on a row in two ways:</p><ul><li>the <strong>⋯</strong> menu on the row;</li><li>the <strong>right-click</strong> context menu.</li></ul><p>Both are equivalent and appear across the main areas of the app.</p><h2 id="top-toolbar" tabindex="-1">Top toolbar <a class="header-anchor" href="#top-toolbar" aria-label="Permalink to &quot;Top toolbar&quot;">​</a></h2><p>Most panels share a common top toolbar with search and extra actions. What appears there depends on the current mode and the kind of data shown.</p><p><img src="'+t+'" alt="Props, область заголовка"></p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>Search is a cross-cutting feature in the main panels.</p><p>The runtime provides a built-in search affordance:</p><ul><li><strong>Ctrl+F</strong> — uses the browser’s or DevTools find‑in‑page behavior (and how it interacts with the panel depends on <a href="/qa-tools/docs/options/display_mode.html">display mode</a> and the structure of the current view).</li></ul><p>For section-specific filters (requests, props, store), see the relevant docs — for example <a href="/qa-tools/docs/network/general.html">Network — working with requests</a>.</p><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard shortcuts&quot;">​</a></h2><p>Common shortcuts:</p><ul><li><strong>Ctrl+F</strong> — search in the current panel (see above);</li><li><strong>Esc</strong> — cancel the current action, e.g. close a detail view or exit <a href="/qa-tools/docs/props/inspect.html">Inspect</a> mode.</li></ul><h2 id="detail-views" tabindex="-1">Detail views <a class="header-anchor" href="#detail-views" aria-label="Permalink to &quot;Detail views&quot;">​</a></h2><p>Many entities open a <strong>detail</strong> view when selected. <strong>Esc</strong> or navigating back returns to the previous UI state.</p><p><img src="'+o+'" alt="Детализация props"></p><h2 id="display-modes" tabindex="-1">Display modes <a class="header-anchor" href="#display-modes" aria-label="Permalink to &quot;Display modes&quot;">​</a></h2><p>Depending on launch context — <strong>Overlay</strong>, <strong>DevTools</strong>, or <strong>Standalone</strong> — layout and chrome can differ slightly while keeping the same overall behavior. See <a href="/qa-tools/docs/options/display_mode.html">Display modes</a>, <a href="/qa-tools/docs/extension.html">Browser extension</a>, and <a href="/qa-tools/docs/standalone.html">Standalone app</a>.</p>',25)])])}const b=r(l,[["render",p]]);export{_ as __pageData,b as default};
